type Comment struct {
	Content string
}

var comments = []Comment{
	{Content: "Hello, World!"},
	{Content: "*Highlighted Text*"},
	// Add more comments here...
}

var commentTmpl *template.Template

func init() {
	commentTmpl = template.Must(template.New("comment").Parse(`
		<div>{{ . | safeHTML }} </div>
	`))
}

func main() {
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		tmpl := template.Must(template.New("comments").Parse(`
			<html>
			<head>
				<title>User Comments</title>
			</head>
			<body>
				{{range .}}
					{{ template "comment" . }}
				{{end}}
			</body>
			</html>
		`))
		tmpl.Execute(w, comments)
	})

	http.ListenAndServe(":8080", nil)
}

func (c *Comment) Render() template.HTML {
	var out template.HTML
	err := commentTmpl.Execute(&out, c)
	if err != nil {
		panic(err)
	}
	return out
}